import { Router } from "express";
import { handleAcceptFriendRequest, handleDiscoverProfiles, handleListFriendRequests, handleListFriends, handleRejectFriendRequest, handleSendFriendRequest } from "../controllers/friendController.js";
import { requireAuth } from "../middleware/auth.js";
export const friendRoutes = Router();
friendRoutes.use(requireAuth);
friendRoutes.get("/requests", handleListFriendRequests);
friendRoutes.post("/requests/:targetProfileId", handleSendFriendRequest);
friendRoutes.post("/requests/:id/accept", handleAcceptFriendRequest);
friendRoutes.post("/requests/:id/reject", handleRejectFriendRequest);
friendRoutes.get("/", handleListFriends);
friendRoutes.get("/discover", handleDiscoverProfiles);
